-- Ken's Hardened V2 Fix

local b64_0xIIIII1 = {}
local char_0xlll1l1='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0x1IlIl1=1,#char_0xlll1l1 do b64_0xIIIII1[char_0xlll1l1:sub(i_0x1IlIl1,i_0x1IlIl1)] = i_0x1IlIl1 - 1 end

function b64_0xIIIII1.dec_0xlIIIII(d_0xlI1I1l)
    d_0xlI1I1l = string.gsub(d_0xlI1I1l, '[^'..char_0xlll1l1..'=]', '')
    local r_0xlIl111 = {}
    for i_0x1IlIl1=1, #d_0xlI1I1l, 4 do
        local c_0xIIlIIl = b64_0xIIIII1[d_0xlI1I1l:sub(i_0x1IlIl1,i_0x1IlIl1)] or 0
        local c_0x11l1l1 = b64_0xIIIII1[d_0xlI1I1l:sub(i_0x1IlIl1+1,i_0x1IlIl1+1)] or 0
        local c_0xI1IIlI, c_0xlIlIII = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlI1I1l:sub(i_0x1IlIl1+2,i_0x1IlIl1+2)
        if ch3 == "=" then has3 = false else c_0xI1IIlI = b64_0xIIIII1[ch3] or 0 end
        local ch4 = d_0xlI1I1l:sub(i_0x1IlIl1+3,i_0x1IlIl1+3)
        if ch4 == "=" then has4 = false else c_0xlIlIII = b64_0xIIIII1[ch4] or 0 end
        local b_0x1l1l1l = c_0xIIlIIl * (2^18) + c_0x11l1l1 * (2^12) + c_0xI1IIlI * (2^6) + c_0xlIlIII
        local b_0xIlIIlI = math.floor(b_0x1l1l1l / (2^16)) % (2^8)
        local b_0xIlI111 = math.floor(b_0x1l1l1l / (2^8)) % (2^8)
        local b_0xIl1lII = b_0x1l1l1l % (2^8)
        table.insert(r_0xlIl111, string.char(b_0xIlIIlI))
        if has3 then table.insert(r_0xlIl111, string.char(b_0xIlI111)) end
        if has4 then table.insert(r_0xlIl111, string.char(b_0xIl1lII)) end
    end
    return table.concat(r_0xlIl111)
end


local function bxor_0xIlI111(a_0xIIII11,b_0xlIlIl1)
    if bit32 then return bit32.bxor(a_0xIIII11,b_0xlIlIl1) end
    local r_0x1IllIl = 0
    for i_0xll1ll1 = 0, 7 do
        local x_0xl1II1I = a_0xIIII11 % 2
        local y_0xIIllII = b_0xlIlIl1 % 2
        if x_0xl1II1I ~= y_0xIIllII then r_0x1IllIl = r_0x1IllIl + (2^i_0xll1ll1) end
        a_0xIIII11 = math.floor(a_0xIIII11 / 2)
        b_0xlIlIl1 = math.floor(b_0xlIlIl1 / 2)
    end
    return r_0x1IllIl
end


local function bxor_str_0xII1ll1(s_0x1lII11, k_0xIl1IlI)
    local r_0xlI1llI = {}
    for i_0xI1llIl=1, #s_0x1lII11 do
        local b_0xlllIII = string.byte(s_0x1lII11, i_0xI1llIl)
        local kb_0x1lllI1 = string.byte(k_0xIl1IlI, (i_0xI1llIl-1) % #k_0xIl1IlI + 1)
        r_0xlI1llI[i_0xI1llIl] = string.char(bxor_0xIlI111(b_0xlllIII, kb_0x1lllI1))
    end
    return table.concat(r_0xlI1llI)
end


local function getkeys_0xll111I()
    local seed = b64_0xIIIII1.dec_0xlIIIII("VzdrZUtxYWY=")
    local k1_enc = b64_0xIIIII1.dec_0xlIIIII("MU0fDxMEVRQ=")
    local k2_enc = b64_0xIIIII1.dec_0xlIIIII("GkUCEjIWGzQ=")
    return bxor_str_0xII1ll1(k1_enc, seed), bxor_str_0xII1ll1(k2_enc, seed)
end


local function cff_0xIIIIl1(a_0xlII1ll)
    local st_0xI1llII = 0
    local res_0xIlI1II = a_0xlII1ll
    while true do
        if st_0xI1llII == 0 then
            res_0xIlI1II = res_0xIlI1II + 1
            st_0xI1llII = 1
        elseif st_0xI1llII == 1 then
            res_0xIlI1II = res_0xIlI1II * 2
            st_0xI1llII = 2
        elseif st_0xI1llII == 2 then
            res_0xIlI1II = res_0xIlI1II - 3
            st_0xI1llII = 3
        else
            break
        end
    end
    return res_0xIlI1II
end


local function chain_0x1l111I(x) return x*2 end
local function chain_0xI1I111(x) return chain_0x1l111I(x)+1 end


local d_0xI1I1II = {
  {op=255, val="", is_enc=true},
}
local pc_0xllIllI = 1
local stk_0xIlllll = {}
stk_0xIlllll._jmp = nil


local disp_0xlllll1 = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xll111I()

local state_0xll1ll1 = 0
while true do
    if state_0xll1ll1 == 0 then  -- FETCH
        if pc_0xllIllI > #d_0xI1I1II then break end
        local inst = d_0xI1I1II[pc_0xllIllI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIIIII1.dec_0xlIIIII(val)
            d = bxor_str_0xII1ll1(d, k2)
            val = bxor_str_0xII1ll1(d, k1)
        end
        stk_0xIlllll._jmp = nil
        pc_0xllIllI = pc_0xllIllI + 1
        cur_op_0xl1IIIl = opcode
        cur_val_0x11I1ll = val
        state_0xll1ll1 = 1

    elseif state_0xll1ll1 == 1 then  -- EXECUTE
        local handler = disp_0xlllll1[cur_op_0xl1IIIl]
        if handler then
            handler(stk_0xIlllll, cur_val_0x11I1ll)
        end
        if stk_0xIlllll._jmp then
            pc_0xllIllI = pc_0xllIllI + stk_0xIlllll._jmp
        end
        state_0xll1ll1 = 0
    else
        break
    end
end
